import {MapContainer,TileLayer,Polyline} from "react-leaflet"
import {useEffect,useState} from "react"
import {getRoute} from "../services/api"

export default function RoutePage(){

const [route,setRoute]=useState([])

useEffect(()=>{
getRoute().then(r=>setRoute(r.data))
},[])

const coords=route.map(r=>[r.Latitude,r.Longitude])

return(
<div>

<h2>Truck Route Optimization</h2>

<MapContainer center={[12.97,77.59]} zoom={11} style={{height:"500px"}}>

<TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"/>

<Polyline positions={coords} color="yellow"/>

</MapContainer>

</div>
)
}
